  "extends": "Node2D",
  "class_name": "PieceRenderer",
  "lines": 373,
  "content": "# PieceRenderer — 单块拼图片渲染
# 三种状态：ACTIVE(可填充)、CANDIDATE(待选择)、HIDDEN(不可见)
extends Node2D
class_name PieceRenderer

enum PieceState { HIDDEN, CANDIDATE, ACTIVE }

## 颜色常量
const COLOR_STATUS_LOCKED := Color(0.3, 0.3, 0.35)
const COLOR_STATUS_UNLOCKED := Color(1.0, 0.85, 0.2)
const COLOR_STATUS_COMPLETED := Color(0.2, 0.9, 0.3)
const COLOR_BORDER_LOCKED := Color(0.1, 0.1, 0.12)
const COLOR_BORDER_UNLOCKED := Color(0.5, 0.45, 0.15)
const COLOR_BORDER_COMPLETED := Color(0.15, 0.5, 0.2)
const COLOR_SLOT_EMPTY := Color(0.8, 0.8, 0.85, 0.5)
const COLOR_SLOT_FILLED := Color(1.0, 1.0, 1.0)
const COLOR_SLOT_LOCKED := Color(0.1, 0.1, 0.1)
const COLOR_OVERLAY_LOCK := Color(0.0, 0.0, 0.0, 0.2)  # 淡暗色遮罩，保留图片预览
const COLOR_OVERLAY_COMPLETE := Color(0.2, 1.0, 0.3, 0.12)

# 渲染节点容器
var _slot_rects: Array[ColorRect] = []
var _bead_rects: Array[ColorRect] = []
var _slot_border_rects: Array[ColorRect] = []
var _click_areas: Array[Control] = []

var _border_rect: ColorRect
var _lock_overlay: ColorRect
var _completed_overlay: ColorRect
var _status_indicator: ColorRect

# 引用数据
var piece_data: PuzzlePiece
var _palette: BeadPalette
var _slot_size: float = 32.0
var _slot_gap: float = 2.0
var _state: PieceState = PieceState.HIDDEN

# 原图引用（完成片显示原图区域）
var _source_image: Image = null
var _source_rect: Rect2i = Rect2i(0, 0, 0, 0)
var _source_texture: TextureRect = null

# 信号
signal slot_clicked(slot_index: int)


func _ready() -> void:
	pass


func setup(data: PuzzlePiece, palette: BeadPalette, slot_size: float = 32.0, slot_gap: float = 2.0) -> void:
	piece_data = data
	_palette = palette
	_slot_size = slot_size
	_slot_gap = slot_gap
	GameLog.info("PieceRenderer", "setup piece(%d,%d) slots=%d locked=%s completed=%s slot_size=%.0f" % [data.grid_x, data.grid_y, data.slots.size(), data.is_locked, data.is_completed, slot_size])
	_render()


func set_grid_position(gx: int, gy: int, piece_pixel_size: float, gap: float = 6.0) -> void:
	position = Vector2(gx * (piece_pixel_size + gap), gy * (piece_pixel_size + gap))


func get_render_size() -> Vector2:
	if piece_data == null:
		return Vector2.ZERO
	var total: float = piece_data.piece_size * (_slot_size + _slot_gap) - _slot_gap + 8
	return Vector2(total, total)


# ===== 渲染 =====

func _render() -> void:
	_clear_all()
	if piece_data == null:
		return

	var psize: int = piece_data.piece_size
	var border_width_out := 4.0  # 外边框宽度
	var inner_size: float = psize * (_slot_size + _slot_gap) - _slot_gap
	var is_locked: bool = piece_data.is_locked
	var is_completed: bool = piece_data.is_completed

	# === 状态条 (内部顶部4px色条) ===
	var status_color: Color
	if is_completed:
		status_color = COLOR_STATUS_COMPLETED
	elif is_locked:
		status_color = COLOR_STATUS_LOCKED
	else:
		status_color = COLOR_STATUS_UNLOCKED
	_status_indicator = _make_rect(Vector2(0, 0), Vector2(inner_size, 4), status_color)
	add_child(_status_indicator)

	# === 外边框 ===
	var border_color: Color
	if is_completed:
		border_color = COLOR_BORDER_COMPLETED
	elif is_locked:
		border_color = COLOR_BORDER_LOCKED
	else:
		border_color = COLOR_BORDER_UNLOCKED
	_border_rect = _make_rect(Vector2(-border_width_out, -border_width_out), Vector2(inner_size + border_width_out * 2, inner_size + border_width_out * 2), border_color)
	add_child(_border_rect)

	# === 槽位 ===
	var border_width := 4
	var bw := float(border_width)
	for y in psize:
		for x in psize:
			var idx := y * psize + x
			var slot: BeadSlot = piece_data.slots[idx]
			var pos := Vector2(x * (_slot_size + _slot_gap), y * (_slot_size + _slot_gap))

			var bg_color := _get_bg_color(slot)

			# 1. 边框层：整槽大小，拼前淡灰，拼后亮白
			var border_col := _get_border_color(slot)
			var bead_border := _make_rect(pos, Vector2(_slot_size, _slot_size), border_col)
			add_child(bead_border)
			_slot_border_rects.append(bead_border)

			# 2. 目标颜色层（缩进 border_width px）
			var bg_inner := _make_rect(pos + Vector2(bw, bw), Vector2(_slot_size - bw * 2, _slot_size - bw * 2), bg_color)
			add_child(bg_inner)
			_slot_rects.append(bg_inner)

			# 3. 豆子层（始终创建，未填充时隐藏）
			var ins := bw + 1.0
			var bead := _make_rect(pos + Vector2(ins, ins), Vector2(_slot_size - ins * 2, _slot_size - ins * 2), Color.TRANSPARENT)
			bead.visible = slot.is_filled
			if slot.is_filled:
				var base: Color = _palette.get_color_by_id(slot.current_color_id)
				bead.color = Color(base.r * 0.85 + 0.15, base.g * 0.85 + 0.15, base.b * 0.85 + 0.15)
			add_child(bead)
			_bead_rects.append(bead)

			# 4. 点击区域
			var click := Control.new()
			click.position = pos
			click.size = Vector2(_slot_size, _slot_size)
			click.mouse_filter = Control.MOUSE_FILTER_STOP
			click.gui_input.connect(_make_click_handler(idx))
			add_child(click)
			_click_areas.append(click)

	# === 锁定遮罩 ===
	if is_locked:
		_lock_overlay = _make_rect(Vector2(-border_width_out, -border_width_out), Vector2(inner_size + border_width_out * 2, inner_size + border_width_out * 2), COLOR_OVERLAY_LOCK)
		add_child(_lock_overlay)
	else:
		_lock_overlay = _make_rect(Vector2.ZERO, Vector2.ZERO, Color.TRANSPARENT)
		_lock_overlay.visible = false
		add_child(_lock_overlay)

	# === 完成遮罩 ===
	if is_completed:
		_completed_overlay = _make_rect(Vector2(-border_width_out, -border_width_out), Vector2(inner_size + border_width_out * 2, inner_size + border_width_out * 2), COLOR_OVERLAY_COMPLETE)
		add_child(_completed_overlay)
	else:
		_completed_overlay = _make_rect(Vector2.ZERO, Vector2.ZERO, Color.TRANSPARENT)
		_completed_overlay.visible = false
		add_child(_completed_overlay)

	GameLog.info("PieceRenderer", "rendered piece(%d,%d) borders=%d rects=%d beads=%d" % [piece_data.grid_x, piece_data.grid_y, _slot_border_rects.size(), _slot_rects.size(), _bead_rects.size()])


# 刷新显示（放豆子后调用）
func refresh() -> void:
	if piece_data == null:
		return

	GameLog.info("PieceRenderer", "refresh piece(%d,%d) locked=%s completed=%s borders=%d" % [piece_data.grid_x, piece_data.grid_y, piece_data.is_locked, piece_data.is_completed, _slot_border_rects.size()])

	var psize: int = piece_data.piece_size
	for y in psize:
		for x in psize:
			var idx := y * psize + x
			if idx >= piece_data.slots.size() or idx >= _slot_rects.size():
				break
			var slot: BeadSlot = piece_data.slots[idx]

			# 更新边框颜色：拼前淡灰，拼后亮白
			if idx < _slot_border_rects.size():
				var prev_border := _slot_border_rects[idx].color
				var new_border := _get_border_color(slot)
				_slot_border_rects[idx].color = new_border
				if prev_border != new_border:
					GameLog.info("PieceRenderer", "  slot[%d] border %s → %s" % [idx, prev_border, new_border])

			# 更新目标颜色背景
			if idx < _slot_rects.size():
				var prev_bg := _slot_rects[idx].color
				var new_bg := _get_bg_color(slot)
				_slot_rects[idx].color = new_bg
				if prev_bg != new_bg:
					GameLog.info("PieceRenderer", "  slot[%d] bg %s → %s" % [idx, prev_bg, new_bg])

			# 更新豆子（始终存在，只需更新颜色和可见性）
			if idx < _bead_rects.size():
				if slot.is_filled:
					var base: Color = _palette.get_color_by_id(slot.current_color_id)
					var bead_color := Color(base.r * 0.85 + 0.15, base.g * 0.85 + 0.15, base.b * 0.85 + 0.15)
					_bead_rects[idx].color = bead_color
					_bead_rects[idx].visible = true
					GameLog.info("PieceRenderer", "  slot[%d] bead %s" % [idx, bead_color])
				else:
					_bead_rects[idx].visible = false

	# 状态条颜色
	if piece_data.is_completed:
		_status_indicator.color = COLOR_STATUS_COMPLETED
	elif piece_data.is_locked:
		_status_indicator.color = COLOR_STATUS_LOCKED
	else:
		_status_indicator.color = COLOR_STATUS_UNLOCKED

	# 外边框颜色
	if piece_data.is_completed:
		_border_rect.color = COLOR_BORDER_COMPLETED
	elif piece_data.is_locked:
		_border_rect.color = COLOR_BORDER_LOCKED
	else:
		_border_rect.color = COLOR_BORDER_UNLOCKED

	# 遮罩
	_lock_overlay.visible = piece_data.is_locked
	_completed_overlay.visible = piece_data.is_completed

	# 完成片：显示原图区域
	if piece_data.is_completed and _source_image != null and _source_texture == null:
		_show_source_image()


# 播放解锁动画（从四周"长出来"）
func play_unlock_animation() -> void:
	GameLog.info("PieceRenderer", "play unlock animation piece(%d,%d)" % [piece_data.grid_x, piece_data.grid_y])
	scale = Vector2(0.0, 0.0)
	var tween := create_tween()
	tween.set_ease(Tween.EASE_OUT)
	tween.set_trans(Tween.TRANS_BACK)
	tween.tween_property(self, "scale", Vector2(1.0, 1.0), 0.5)


# 播放缩回动画（候选被取消时）
func play_retreat_animation() -> void:
	GameLog.info("PieceRenderer", "play retreat animation piece(%d,%d)" % [piece_data.grid_x, piece_data.grid_y])
	var tween := create_tween()
	tween.set_ease(Tween.EASE_IN)
	tween.set_trans(Tween.TRANS_BACK)
	tween.tween_property(self, "scale", Vector2(0.0, 0.0), 0.3)
	tween.tween_callback(func() -> void: visible = false)


# ===== 状态管理 =====

func set_state(new_state: PieceState) -> void:
	if _state == new_state:
		return
	var old_state := _state
	_state = new_state
	GameLog.info("PieceRenderer", "piece(%d,%d) state %d→%d" % [piece_data.grid_x, piece_data.grid_y, old_state, new_state])
	_apply_state_visual()


## 设置原图引用（完成片显示原图区域）
func setup_source_image(img: Image, gx: int, gy: int, bead_pixels: int, slot_size: float) -> void:
	if img == null:
		return
	_source_image = img
	var px := gx * bead_pixels
	var py := gy * bead_pixels
	var pw := bead_pixels
	var ph := bead_pixels
	_source_rect = Rect2i(px, py, pw, ph)



func get_state() -> PieceState:
	return _state


func _apply_state_visual() -> void:
	if not piece_data:
		return
	match _state:
		PieceState.HIDDEN:
			# 锁定片：显示淡色图片预览（让玩家看到目标图案）
			modulate = Color(0.6, 0.6, 0.6, 0.5)
		PieceState.CANDIDATE:
			# 候选片：稍微亮一点，提示可以选择
			modulate = Color(1.1, 1.1, 1.05, 1.0)
		PieceState.ACTIVE:
			# 活跃片：正常亮度
			modulate = Color(1.0, 1.0, 1.0, 1.0)
	GameLog.info("PieceRenderer", "piece(%d,%d) state=%s modulate=%s" % [piece_data.grid_x, piece_data.grid_y, PieceState.keys()[_state], modulate])
	# 锁定遮罩：只对锁定片显示，但透明度降低让预览可见
	if _lock_overlay:
		_lock_overlay.visible = piece_data.is_locked
		if piece_data.is_locked:
			_lock_overlay.color = Color(0, 0, 0, 0.2)  # 淡淡的暗色遮罩


# ===== 内部方法 =====

func _show_source_image() -> void:
	## 从原图裁剪对应区域，缩放到片大小，显示为 TextureRect
	var region := Image.new()
	region = _source_image.get_region(_source_rect)
	# 缩放到片实际像素大小
	var inner_size := float(piece_data.piece_size) * _slot_size + float(piece_data.piece_size - 1) * _slot_gap
	region.resize(int(inner_size), int(inner_size), Image.INTERPOLATE_NEAREST)
	var tex := ImageTexture.create_from_image(region)
	_source_texture = TextureRect.new()
	_source_texture.texture = tex
	_source_texture.position = Vector2.ZERO
	_source_texture.size = Vector2(inner_size, inner_size)
	_source_texture.z_index = 100  # 在所有槽位之上
	add_child(_source_texture)
	GameLog.info("PieceRenderer", "source image shown for piece(%d,%d)" % [piece_data.grid_x, piece_data.grid_y])


func _get_border_color(slot: BeadSlot) -> Color:
	if piece_data.is_locked:
		return COLOR_SLOT_LOCKED
	if slot.is_filled:
		return COLOR_SLOT_FILLED
	else:
		return COLOR_SLOT_EMPTY


func _get_bg_color(slot: BeadSlot) -> Color:
	if _palette == null:
		return Color(0.15, 0.15, 0.15)  # fallback
	var target: Color = _palette.get_color_by_id(slot.target_color_id)

	if piece_data.is_locked:
		return Color(target.r * 0.4, target.g * 0.4, target.b * 0.4, 0.6)  # 锁定片：淡色预览
	elif piece_data.is_completed:
		return target
	else:
		if slot.is_filled:
			return Color(target.r * 0.9 + 0.1, target.g * 0.9 + 0.1, target.b * 0.9 + 0.1)  # filled: bright
		else:
			return Color(target.r * 0.45, target.g * 0.45, target.b * 0.45)  # unfilled: 45%


func _make_rect(pos: Vector2, size: Vector2, color: Color) -> ColorRect:
	var rect := ColorRect.new()
	rect.position = pos
	rect.size = size
	rect.color = color
	return rect


func _make_click_handler(idx: int) -> Callable:
	return func(event: InputEvent) -> void:
		GameLog.info("PieceRenderer", "click event idx=%d type=%s" % [idx, event.get_class()])
		if event is InputEventMouseButton and event.pressed and event.button_index == MOUSE_BUTTON_LEFT:
			slot_clicked.emit(idx)
		elif event is InputEventScreenTouch and event.pressed:
			slot_clicked.emit(idx)


func _clear_all() -> void:
	for c in get_children():
		c.queue_free()
	_slot_rects.clear()
	_bead_rects.clear()
	_slot_border_rects.clear()
	_click_areas.clear()
"
}

